bool GPUOverlappedTransfer::traditional_transfer(void* host_data, void* device_data, size_t total_size) {
    start_timing();

    size_t chunk_size = config_.chunk_size_bytes;
    size_t num_chunks = (total_size + chunk_size - 1) / chunk_size;

    // Traditional multi-stream transfer without overlap
    for (size_t i = 0; i < num_chunks; ++i) {
        size_t offset = i * chunk_size;
        size_t current_chunk_size = std::min(chunk_size, total_size - offset);

        // Use round-robin stream assignment
        int stream_idx = i % config_.num_streams;

        cudaMemcpyAsync(
            static_cast<char*>(device_data) + offset,
            static_cast<char*>(host_data) + offset,
            current_chunk_size,
            cudaMemcpyHostToDevice,
            streams_[stream_idx]
        );
    }

    // Wait for all transfers to complete
    for (auto& stream : streams_) {
        cudaStreamSynchronize(stream);
    }

    end_timing();
    calculate_metrics(total_size);

    return true;
}

void GPUOverlappedTransfer::simulate_compute_work(void* device_data, size_t size, cudaStream_t stream) {
    if (size == 0 || device_data == nullptr) {
        return;
    }

    uint8_t* byte_ptr = static_cast<uint8_t*>(device_data);
    size_t word_count = size / sizeof(uint32_t);
    size_t tail_bytes = size % sizeof(uint32_t);

    if (word_count > 0) {
        const int threads_per_block = 256;
        int max_blocks = 4096;
        int blocks = static_cast<int>((word_count + threads_per_block - 1) / threads_per_block);
        blocks = std::min(blocks, max_blocks);
        uint32_t rounds = static_cast<uint32_t>(std::max<size_t>(2, std::min<size_t>(8, word_count / 65536 + 2)));
        OverlapComputeKernel<<<blocks, threads_per_block, 0, stream>>>(
            reinterpret_cast<uint32_t*>(byte_ptr), word_count, rounds);
        ThrowCudaError("OverlapComputeKernel launch", cudaGetLastError());
    }

    if (tail_bytes > 0) {
        const int tail_threads = 128;
        int blocks = static_cast<int>((tail_bytes + tail_threads - 1) / tail_threads);
        OverlapComputeTailKernel<<<blocks, tail_threads, 0, stream>>>(byte_ptr + (word_count * sizeof(uint32_t)), tail_bytes);
        ThrowCudaError("OverlapComputeTailKernel launch", cudaGetLastError());
    }
}

