void GPUOverlappedTransfer::start_timing() {
    session_start_ = std::chrono::steady_clock::now();
}

void GPUOverlappedTransfer::end_timing() {
    auto session_end = std::chrono::steady_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::microseconds>(session_end - session_start_);

    last_metrics_.total_time_ms = duration.count() / 1000.0;
}

void GPUOverlappedTransfer::calculate_metrics(size_t total_size) {
    // Calculate bandwidth
    if (last_metrics_.total_time_ms > 0) {
        double seconds = last_metrics_.total_time_ms / 1000.0;
        last_metrics_.transfer_bandwidth_gb_s = (total_size / (1024.0 * 1024.0 * 1024.0)) / seconds;
    }

    // Calculate overlap efficiency (estimated)
    double theoretical_sequential_time = (total_size / (8.5 * 1024.0 * 1024.0)) * 1000.0; // Based on 8.5 GB/s baseline
    double actual_time = last_metrics_.total_time_ms;
    last_metrics_.overlap_efficiency_percent = ((theoretical_sequential_time - actual_time) / theoretical_sequential_time) * 100.0;

    last_metrics_.total_bytes_transferred = total_size;
}

