template <typename T, size_t N>
void AppendArray(std::vector<uint8_t> &buffer, const T (&value)[N])
{
    const uint8_t *ptr = reinterpret_cast<const uint8_t *>(value);
    buffer.insert(buffer.end(), ptr, ptr + sizeof(T) * N);
}

void SerializeKangarooPayload(const TH_PARAM *threads,
                              int nbThread,
                              std::vector<uint8_t> &buffer,
                              uint64_t &totalKangaroos)
{
    buffer.clear();
    AppendValue(buffer, static_cast<uint32_t>(nbThread));
    size_t total_offset = buffer.size();
    AppendValue(buffer, static_cast<uint64_t>(0)); // placeholder

    uint64_t total = 0;
    for (int i = 0; i < nbThread; ++i)
    {
        AppendValue(buffer, threads[i].nbKangaroo);
        total += threads[i].nbKangaroo;

        for (uint64_t k = 0; k < threads[i].nbKangaroo; ++k)
        {
            AppendArray(buffer, threads[i].px[k].bits64);
            AppendArray(buffer, threads[i].py[k].bits64);
            AppendArray(buffer, threads[i].distance[k].bits64);
        }
    }

    std::memcpy(buffer.data() + total_offset, &total, sizeof(total));
    totalKangaroos = total;
}
