CheckpointWriter::CheckpointWriter(const std::string& filename)
    : filename(filename), file(nullptr, [](FILE* f) { if (f) fclose(f); }), use_compression(false)
    , validate_checksums(true), compression_level(1), target_version_(CHECKPOINT_VERSION)
{
}

CheckpointWriter::~CheckpointWriter()
{
    // RAII handles automatic cleanup
}

CheckpointError CheckpointWriter::WriteCheckpoint(uint64_t totalCount, double totalTime,
                                                     const HashTable& hashTable,
                                                     const TH_PARAM* threads,
                                                     int nbThread, uint32_t dpSize)
{
    if (!file)
    {
        FILE* rawFile = fopen(filename.c_str(), "wb");
        if (!rawFile)
        {
            return CHECKPOINT_FILE_ERROR;
        }
        file.reset(rawFile);
    }

    // Initialize header
    CheckpointHeader header;
    InitializeHeader(header, totalCount, totalTime, dpSize);

    // Write header placeholder (will update after writing data)
    uint64_t header_pos = GetCurrentPosition();
    if (!WriteData(&header, sizeof(header)))
    {
        return CHECKPOINT_FILE_ERROR;
    }

    // Write hash table
    if (!WriteHashTable(hashTable))
    {
        return CHECKPOINT_FILE_ERROR;
    }

    // Write kangaroo states
    if (!WriteKangarooStates(threads, nbThread))
    {
        return CHECKPOINT_FILE_ERROR;
    }

    // Finalize and update header
    FinalizeHeader(header);
    SeekToPosition(header_pos);
    if (!WriteData(&header, sizeof(header)))
    {
        return CHECKPOINT_FILE_ERROR;
    }

    FlushData();
    return CHECKPOINT_OK;
}

CheckpointError CheckpointWriter::WriteHeader(const CheckpointHeader& header)
{
    if (!WriteData(&header, sizeof(header)))
