#include "RAIIMemoryManager.h"
#include <cstdlib>
#include <cstring>
#include <iostream>

namespace kangaroo {
namespace memory {

// ============================================================================
// RAIIMemoryManager Implementation
// ============================================================================

void* RAIIMemoryManager::AllocateHostRaw(size_t size) {
    void* ptr = std::malloc(size);
    if (ptr) {
        UpdateStats(size, true);
    }
    return ptr;
}

void* RAIIMemoryManager::AllocateAlignedRaw(size_t size, size_t alignment) {
    void* ptr = nullptr;
#ifdef _WIN32
    ptr = _aligned_malloc(size, alignment);
#else
    if (posix_memalign(&ptr, alignment, size) != 0) {
        ptr = nullptr;
    }
#endif
    if (ptr) {
        UpdateStats(size, true);
    }
    return ptr;
}

void RAIIMemoryManager::FreeHostRaw(void* ptr) {
    if (ptr) {
        std::free(ptr);
    }
}

void RAIIMemoryManager::FreeAlignedRaw(void* ptr) {
    if (ptr) {
#ifdef _WIN32
        _aligned_free(ptr);
#else
        std::free(ptr);
#endif
    }
}

void RAIIMemoryManager::RecordAllocation(void* ptr, size_t size, MemoryType type,
                                        const std::string& tag,
                                        const std::string& file,
                                        int line) {
    if (!tracking_enabled_ || !ptr) return;

    std::lock_guard<std::mutex> lock(allocations_mutex_);

    AllocationInfo info;
    info.ptr = ptr;
    info.size = size;
    info.type = type;
    info.tag = tag;
    info.alloc_time = std::chrono::steady_clock::now();
    info.file = file;
    info.line = line;
    info.thread_id = std::this_thread::get_id();

    allocations_[ptr] = info;

    UpdateStats(size, true);
}

void RAIIMemoryManager::RecordDeallocation(void* ptr) {
    if (!tracking_enabled_ || !ptr) return;

    std::lock_guard<std::mutex> lock(allocations_mutex_);

    auto it = allocations_.find(ptr);
    if (it != allocations_.end()) {
        UpdateStats(it->second.size, false);
        allocations_.erase(it);
    }
}

void RAIIMemoryManager::UpdateStats(size_t size, bool is_allocation) {
    if (is_allocation) {
        stats_.total_allocated += size;
        stats_.current_usage += size;
        stats_.allocation_count++;
        UpdatePeakUsage();
    } else {
        stats_.total_freed += size;
        stats_.current_usage -= size;
        stats_.deallocation_count++;
    }
}

void RAIIMemoryManager::UpdatePeakUsage() {
    size_t current = stats_.current_usage.load();
    size_t peak = stats_.peak_usage.load();

    while (current > peak) {
        if (stats_.peak_usage.compare_exchange_weak(peak, current)) {
            break;
        }
    }
}

error::ErrorContext RAIIMemoryManager::CreateErrorContext(const std::string& msg,
                                                          size_t size,
                                                          const std::string& file,
                                                          int line) const {
    error::ErrorContext ctx;
    ctx.message = msg + " (size: " + std::to_string(size) + " bytes)";
    ctx.file = file;
    ctx.line = line;
    return ctx;
}

void RAIIMemoryManager::PrintStats(std::ostream& os) const {
    os << "=== Memory Statistics ===\n";
    os << "Total Allocated: " << stats_.total_allocated.load() << " bytes\n";
    os << "Total Freed: " << stats_.total_freed.load() << " bytes\n";
    os << "Current Usage: " << stats_.current_usage.load() << " bytes\n";
    os << "Peak Usage: " << stats_.peak_usage.load() << " bytes\n";
    os << "Allocation Count: " << stats_.allocation_count.load() << "\n";
    os << "Deallocation Count: " << stats_.deallocation_count.load() << "\n";
}

void RAIIMemoryManager::ResetStats() {
    stats_.total_allocated = 0;
    stats_.total_freed = 0;
    stats_.current_usage = 0;
    stats_.peak_usage = 0;
    stats_.allocation_count = 0;
    stats_.deallocation_count = 0;
    stats_.reallocation_count = 0;
}

std::vector<AllocationInfo> RAIIMemoryManager::GetAllocations() const {
    std::lock_guard<std::mutex> lock(allocations_mutex_);

    std::vector<AllocationInfo> result;
    result.reserve(allocations_.size());

    for (const auto& pair : allocations_) {
        result.push_back(pair.second);
    }

    return result;
}

