/**
 * @brief Time and timing utilities
 * 提供高精度时间测量和时间格式化功能
 */
class TimeUtils {
public:
    // 获取当前时间（毫秒）
    static double GetCurrentTimeMs() {
        auto now = std::chrono::high_resolution_clock::now();
        auto duration = now.time_since_epoch();
        return std::chrono::duration<double, std::milli>(duration).count();
    }

    // 获取当前时间（微秒）
    static uint64_t GetCurrentTimeUS() {
        auto now = std::chrono::high_resolution_clock::now();
        auto duration = now.time_since_epoch();
        return std::chrono::duration_cast<std::chrono::microseconds>(duration).count();
    }

    // 获取当前进程ID
    static uint64_t GetPID() {
#ifdef WIN64
        return static_cast<uint64_t>(GetCurrentProcessId());
#else
        return static_cast<uint64_t>(getpid());
#endif
    }

    // 格式化时间间隔（毫秒）
    static std::string FormatDuration(double ms) {
        if (ms < 1000) {
            return std::to_string(static_cast<int>(ms)) + "ms";
        } else if (ms < 60000) {
            return std::to_string(static_cast<int>(ms / 1000)) + "." + 
                   std::to_string(static_cast<int>((ms - static_cast<int>(ms / 1000) * 1000) / 100)) + "s";
        } else if (ms < 3600000) {
            int minutes = static_cast<int>(ms / 60000);
            int seconds = static_cast<int>((ms - minutes * 60000) / 1000);
            return std::to_string(minutes) + "m " + std::to_string(seconds) + "s";
        } else {
            int hours = static_cast<int>(ms / 3600000);
            int minutes = static_cast<int>((ms - hours * 3600000) / 60000);
            return std::to_string(hours) + "h " + std::to_string(minutes) + "m";
        }
    }

    // 获取当前时间戳字符串
    static std::string GetCurrentTimestamp() {
        auto now = std::chrono::system_clock::now();
        auto time_t = std::chrono::system_clock::to_time_t(now);
        std::tm tm_time;

#ifdef WIN64
        localtime_s(&tm_time, &time_t);
#else
        localtime_r(&time_t, &tm_time);
#endif

        std::ostringstream oss;
        oss << std::put_time(&tm_time, "%Y-%m-%d %H:%M:%S");
        return oss.str();
    }
};

/**
 * @brief File system utilities
