 */
class FileUtils {
public:
    // 检查文件是否存在
    static bool FileExists(const std::string& path) {
        std::ifstream file(path);
        return file.good();
    }

    // 检查目录是否存在
    static bool DirectoryExists(const std::string& path) {
#ifdef WIN64
        DWORD attributes = GetFileAttributesA(path.c_str());
        return (attributes != INVALID_FILE_ATTRIBUTES) && (attributes & FILE_ATTRIBUTE_DIRECTORY);
#else
        struct stat info;
        return (stat(path.c_str(), &info) == 0) && S_ISDIR(info.st_mode);
#endif
    }

    // 创建单级目录
    static bool CreateDirectory(const std::string& path) {
#ifdef WIN64
        return _mkdir(path.c_str()) == 0 || errno == EEXIST;
#else
        return mkdir(path.c_str(), 0755) == 0 || errno == EEXIST;
#endif
    }

    // 递归创建多级目录
    static bool CreateDirectories(const std::string& path) {
        // 处理Windows和Unix路径分隔符
        std::string normalized_path = path;
        for (char& c : normalized_path) {
            if (c == '\\') c = '/';
        }

        std::vector<std::string> parts;
        size_t start = 0;
        size_t end = normalized_path.find('/');

        while (end != std::string::npos) {
            if (end > start) {
                parts.push_back(normalized_path.substr(start, end - start));
            }
            start = end + 1;
            end = normalized_path.find('/', start);
        }

        if (start < normalized_path.length()) {
            parts.push_back(normalized_path.substr(start));
        }

        std::string current_path;
        for (const auto& part : parts) {
            if (part.empty() || part == ".") continue;

            if (!current_path.empty() && current_path.back() != '/') {
                current_path += "/";
            }
            current_path += part;

            if (!DirectoryExists(current_path)) {
                if (!CreateDirectory(current_path)) {
                    return false;
                }
            }
        }

        return true;
    }

    // 获取文件大小
    static size_t GetFileSize(const std::string& path) {
        std::ifstream file(path, std::ifstream::ate | std::ifstream::binary);
        if (!file.is_open()) {
            return 0;
        }

        file.seekg(0, std::ios::end);
        return static_cast<size_t>(file.tellg());
    }

    // 获取文件扩展名
    static std::string GetFileExtension(const std::string& path) {
        size_t dot_pos = path.find_last_of('.');
        if (dot_pos == std::string::npos) {
            return "";
        }
