+  if (current == 0) return kInitialBucketCapacity;
+  uint64_t grown = static_cast<uint64_t>(current) * 3 / 2 + kGrowthPadding;
+  if (grown <= current) grown = static_cast<uint64_t>(current) + kGrowthPadding;
+  if (grown > MAX_ITEMS_PER_BUCKET) grown = MAX_ITEMS_PER_BUCKET;
